mapper.select:
SELECT ci.id, ci.complaint_no, ci.order_no, ci.user_id, ci.user_nickname, ci.user_phone, ci.merchant_id, ci.merchant_name, ci.complaint_type, CASE ci.complaint_type WHEN 1 THEN '商品质量问题' WHEN 2 THEN '服务态度问题' WHEN 3 THEN '配送问题' WHEN 4 THEN '退款问题' WHEN 5 THEN '其他' END AS complaintTypeName, ci.complaint_content, ci.contact_phone, ci.image_urls, ci.status, CASE ci.status WHEN 0 THEN '待处理' WHEN 1 THEN '处理中' WHEN 2 THEN '已解决' WHEN 3 THEN '已关闭' END AS statusName, ci.handler_id, ci.handler_name, ci.handle_time, ci.handle_result, ci.user_satisfied, ci.user_feedback, ci.create_time, ci.update_time FROM complaint_info ci WHERE ci.deleted = 0
AND ci.complaint_no LIKE CONCAT('%', #{query.complaintNo}, '%')
AND ci.order_no LIKE CONCAT('%', #{query.orderNo}, '%')
AND ci.user_id = #{query.userId}
AND ci.merchant_id = #{query.merchantId}
AND ci.complaint_type = #{query.complaintType}
AND ci.status = #{query.status}
AND DATE(ci.create_time) >= #{query.startDate}
AND DATE(ci.create_time) <= #{query.endDate}
ORDER BY ci.create_time DESC
